import { AppMode, Question } from './types';
import { questions as systemQuestions } from './hooks/data';
import { questions as skeletonQuestions } from './hooks/data_skeleton';
import { questions as ch10Questions } from './hooks/data_ch10';
import { questions as ch11Concepts } from './hooks/data_ch11_concepts';
import { questions as ch11Diagrams } from './hooks/data_ch11_diagrams';
import { ShieldCheck, DatabaseZap, Trash2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [isSyncing, setIsSyncing] = useState(false);

  // PRIMARY DATA VAULT: Loads user modifications from local storage (import/export only)
  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v4');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Critical: Data Vault Access Denied", e);
      return [];
    }
  });

  // AUTO-PERSISTENCE: Every change to the vault is instantly locked into storage
  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v4', JSON.stringify(userVault));

    // UI Feedback for Syncing
    setIsSyncing(true);
    const timer = setTimeout(() => setIsSyncing(false), 1200);
    return () => clearTimeout(timer);
  }, [userVault]);

  // KNOWLEDGE BASE COMPILER: Merges system data with user data and REMOVES DUPLICATES
  const allQuestions = useMemo(() => {
    // 1. Create a Master List (User Vault takes priority over System Data)
    const combinedList = [
      ...userVault, 
      ...systemQuestions, 
      ...skeletonQuestions, 
      ...ch10Questions,
      ...ch11Concepts, // High Priority: Muscular System (Concepts)
      ...ch11Diagrams  // High Priority: Muscular System (Diagrams)
    ];

    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();
    const seenText = new Set<string>();

    combinedList.forEach(q => {
      // Normalize text for duplicate detection (ignore case and whitespace)
      const normalizedText = q.questionText.toLowerCase().trim();

      // Strict Deduplication Logic:
      // 1. Check if ID already exists
      // 2. Check if exact Question Text already exists (prevents content duplicates with different IDs)
      if (!seenIds.has(q.id) && !seenText.has(normalizedText)) {
        seenIds.add(q.id);
        seenText.add(normalizedText);
        uniqueQuestions.push(q);
      }
    });

    return uniqueQuestions;
  }, [userVault]);

  const exportVault = () => {
    const dataStr = JSON.stringify(userVault, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
    const date = new Date().toISOString().split('T')[0];
    const link = document.createElement('a');
    link.setAttribute('href', dataUri);
    link.setAttribute('download', `ANATOMY_MASTER_VAULT_${date}.json`);
    link.click();
  };

  const importVault = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const imported = JSON.parse(e.target?.result as string) as Question[];
        if (Array.isArray(imported)) {
          setUserVault(prev => {
            const currentMap = new Map(prev.map(q => [q.id, q]));
            imported.forEach(q => currentMap.set(q.id, q)); // Merge by ID
            return Array.from(currentMap.values());
          });
          alert("Vault Re-Synchronized: Import Successful.");
        }
      } catch (err) {
        alert("Integrity Error: File format corrupted.");
      }
    };
    reader.readAsText(file);
  };

  const clearUserData = () => {
    if (confirm("WARNING: This will delete all your custom questions, progress, and saved edits from the Local Vault. The core system questions will remain. Are you sure?")) {
      setUserVault([]);
      localStorage.removeItem('anatomy_ultimate_vault_v4');
      localStorage.removeItem('anatomy_quiz_session_v1');
      localStorage.removeItem('anatomy_quiz_mistakes_v1');
      window.location.reload();
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans text-slate-900 selection:bg-blue-100 selection:text-blue-900">
      <Header currentMode={currentMode} onModeChange={(mode) => {
        setCurrentMode(mode);
      }} />

      {/* GLOBAL SYNC HUD */}
      <div className={`fixed bottom-12 right-12 z-[100] transition-all duration-700 pointer-events-none ${isSyncing ? 'translate-y-0 opacity-100' : 'translate-y-12 opacity-0'}`}>
        <div className="bg-slate-950 text-white px-8 py-4 rounded-[2rem] shadow-[0_20px_60px_rgba(0,0,0,0.3)] flex items-center gap-4 border border-slate-800">
          <div className="relative">
            <div className="absolute inset-0 bg-blue-500 rounded-full blur animate-ping opacity-50"></div>
            <DatabaseZap size={20} className="text-blue-400 relative z-10" />
          </div>
          <div className="flex flex-col">
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-blue-400">Knowledge Locked</span>
            <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Global Vault Synced</span>
          </div>
          <ShieldCheck size={20} className="text-emerald-400 ml-2" />
        </div>
      </div>

      <main className="flex-1 relative">
        <div className={currentMode === AppMode.FLASHCARDS ? 'block py-6' : 'hidden'}>
          <Flashcards data={allQuestions} />
        </div>
        <div className={currentMode === AppMode.QUIZ ? 'block h-full' : 'hidden'}>
          <Quiz data={allQuestions} />
        </div>
        <div className={currentMode === AppMode.LIST ? 'block py-6' : 'hidden'}>
          <QuestionList 
            data={allQuestions} 
            onExport={exportVault}
            onImport={importVault}
          />

          <div className="flex justify-center mt-12 mb-8">
             <button 
               onClick={clearUserData}
               className="flex items-center gap-2 text-xs font-bold text-red-400 hover:text-red-600 uppercase tracking-widest transition-colors opacity-60 hover:opacity-100"
             >
               <Trash2 size={14} /> Factory Reset (Clear Local Vault)
             </button>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, Volume2, Download, Upload, ShieldCheck, Database, 
  Filter, ArrowUpDown, X, ChevronDown, Check, LayoutGrid, List
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import Button from './Button';

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
  onImport: (e: React.ChangeEvent<HTMLInputElement>) => void;
}

const ITEMS_PER_PAGE = 20; // Reduced for better mobile performance

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport, onImport }) => {
  const [search, setSearch] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');
  const [isFilterMenuOpen, setIsFilterMenuOpen] = useState(false);
  const { speak } = useSpeech();

  const stripHtml = (html: string) => {
    const tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  };

  // 1. Extract Categories
  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'Uncategorized'));
    return ['All', ...Array.from(cats).sort()];
  }, [data]);

  // 2. Filter & Sort Data
  const processedData = useMemo(() => {
    let result = data;

    // Filter by Category
    if (selectedCategory !== 'All') {
      result = result.filter(q => (q.category || 'Uncategorized') === selectedCategory);
    }

    // Filter by Search
    if (search.trim()) {
      const lowerSearch = search.toLowerCase();
      result = result.filter(q => 
        q.questionText.toLowerCase().includes(lowerSearch) || 
        q.answerText.toLowerCase().includes(lowerSearch)
      );
    }

    // Sort
    if (sortOrder === 'asc') {
      result = [...result].sort((a, b) => stripHtml(a.questionText).localeCompare(stripHtml(b.questionText)));
    } else if (sortOrder === 'desc') {
      result = [...result].sort((a, b) => stripHtml(b.questionText).localeCompare(stripHtml(a.questionText)));
    }

    return result;
  }, [data, selectedCategory, search, sortOrder]);

  // Reset pagination on filter change
  useEffect(() => {
    setCurrentPage(1);
  }, [search, selectedCategory, sortOrder]);

  // Pagination Logic
  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice(
    (currentPage - 1) * ITEMS_PER_PAGE,
    currentPage * ITEMS_PER_PAGE
  );

  const handlePageChange = (newPage: number) => {
    setCurrentPage(newPage);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="max-w-7xl mx-auto w-full px-4 py-6 md:py-8 space-y-6 pb-32">

      {/* --- HEADER DASHBOARD (Responsive) --- */}
      <div className="bg-white rounded-3xl p-6 md:p-8 border border-slate-200 shadow-xl overflow-hidden relative group">
        <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
          <Database size={200} />
        </div>

        <div className="flex flex-col md:flex-row justify-between gap-6 relative z-10">
          <div className="space-y-2">
            <h2 className="text-2xl md:text-3xl font-black text-slate-900 tracking-tight">
              Knowledge <span className="text-blue-600">Index</span>
            </h2>
            <div className="flex flex-wrap items-center gap-4 text-xs font-bold text-slate-500 uppercase tracking-widest">
              <span className="flex items-center gap-1"><Database size={14} className="text-blue-500" /> {data.length.toLocaleString()} Records</span>
              <span className="flex items-center gap-1"><ShieldCheck size={14} className="text-emerald-500" /> Synced</span>
            </div>
          </div>

          <div className="flex gap-3 w-full md:w-auto">
            <button 
              onClick={onExport}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-3 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl font-bold text-xs uppercase tracking-wider transition-all"
            >
              <Download size={16} /> Backup
            </button>
            <label className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-3 bg-slate-900 hover:bg-slate-800 text-white rounded-xl font-bold text-xs uppercase tracking-wider cursor-pointer transition-all shadow-lg">
              <Upload size={16} /> Restore
              <input type="file" className="hidden" accept=".json" onChange={onImport} />
            </label>
          </div>
        </div>
      </div>

      {/* --- CONTROLS BAR (Sticky) --- */}
      <div className="sticky top-20 z-30 space-y-4">
        {/* Search Bar */}
        <div className="relative shadow-lg rounded-2xl">
          <input 
            type="text" 
            placeholder="Search terms, definitions..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-12 pr-4 py-4 rounded-2xl border-2 border-slate-200 bg-white text-base font-semibold text-slate-800 focus:border-blue-500 focus:ring-4 ring-blue-50 outline-none transition-all placeholder:text-slate-400"
          />
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          {search && (
            <button onClick={() => setSearch('')} className="absolute right-4 top-1/2 -translate-y-1/2 p-1 bg-slate-100 hover:bg-red-100 text-slate-400 hover:text-red-500 rounded-full transition-colors">
              <X size={14} />
            </button>
          )}
        </div>

        {/* Filters & Sort */}
        <div className="flex flex-col md:flex-row gap-3">
          {/* Category Dropdown */}
          <div className="relative flex-1">
            <button 
              onClick={() => setIsFilterMenuOpen(!isFilterMenuOpen)}
              className="w-full flex items-center justify-between px-4 py-3 bg-white border border-slate-200 rounded-xl font-bold text-sm text-slate-700 shadow-sm hover:border-blue-300 transition-all"
            >
              <span className="flex items-center gap-2 truncate">
                <Filter size={16} className="text-blue-500" />
                <span className="truncate">{selectedCategory}</span>
              </span>
              <ChevronDown size={16} className={`text-slate-400 transition-transform ${isFilterMenuOpen ? 'rotate-180' : ''}`} />
            </button>

            {isFilterMenuOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsFilterMenuOpen(false)}></div>
                <div className="absolute top-full left-0 mt-2 w-full bg-white border border-slate-200 rounded-xl shadow-2xl z-20 max-h-60 overflow-y-auto custom-scrollbar p-2">
                  {categories.map(cat => (
                    <button
                      key={cat}
                      onClick={() => { setSelectedCategory(cat); setIsFilterMenuOpen(false); }}
                      className={`w-full text-left px-3 py-2 rounded-lg text-sm font-semibold transition-colors flex items-center justify-between ${selectedCategory === cat ? 'bg-blue-50 text-blue-700' : 'text-slate-600 hover:bg-slate-50'}`}
                    >
                      {cat}
                      {selectedCategory === cat && <Check size={14} />}
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>

          {/* Sort Button */}
          <button 
            onClick={() => setSortOrder(prev => prev === 'default' ? 'asc' : prev === 'asc' ? 'desc' : 'default')}
            className={`flex items-center justify-center gap-2 px-6 py-3 rounded-xl font-bold text-sm border transition-all ${sortOrder !== 'default' ? 'bg-blue-50 text-blue-700 border-blue-200' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
          >
            <ArrowUpDown size={16} />
            {sortOrder === 'default' ? 'Default' : sortOrder === 'asc' ? 'A-Z' : 'Z-A'}
          </button>
        </div>
      </div>

      {/* --- CONTENT LIST (Card Layout) --- */}
      <div className="space-y-4">
        {processedData.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-slate-300">
            <Search size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-slate-400 font-bold">No results found matching your criteria.</p>
            <button onClick={() => { setSearch(''); setSelectedCategory('All'); }} className="mt-4 text-blue-600 font-bold text-sm hover:underline">Clear Filters</button>
          </div>
        ) : (
          currentData.map((q) => (
            <div key={q.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow overflow-hidden flex flex-col md:flex-row">
              {/* Image Section (Mobile: Top, Desktop: Left) */}
              {q.questionImage && (
                <div className="w-full md:w-48 h-48 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-4 shrink-0">
                  <img src={q.questionImage} alt="Diagram" className="max-w-full max-h-full object-contain rounded-lg" loading="lazy" />
                </div>
              )}

              {/* Content Section */}
              <div className="p-5 md:p-6 flex-1 flex flex-col gap-4">
                <div className="flex items-start justify-between gap-4">
                  <span className="text-[10px] font-black uppercase text-blue-500 bg-blue-50 px-2 py-1 rounded border border-blue-100 tracking-wider">
                    {q.category || 'General'}
                  </span>
                  <button 
                    onClick={() => speak(stripHtml(q.questionText), q.id)}
                    className="text-slate-400 hover:text-blue-600 transition-colors p-1"
                  >
                    <Volume2 size={18} />
                  </button>
                </div>

                <div className="space-y-4">
                  <div>
                    <h3 
                      className="text-lg font-bold text-slate-800 leading-snug"
                      dangerouslySetInnerHTML={{ __html: q.questionText }}
                    />
                  </div>

                  <div className="pl-4 border-l-2 border-blue-500 py-1">
                    <p 
                      className="text-base font-medium text-slate-600 leading-relaxed"
                      dangerouslySetInnerHTML={{ __html: q.answerText }}
                    />
                  </div>

                  {q.explanation && (
                    <div className="bg-slate-50 p-3 rounded-lg border border-slate-100 text-sm text-slate-500 italic">
                      <span className="font-bold not-italic text-slate-400 text-xs uppercase mr-2">Note:</span>
                      <span dangerouslySetInnerHTML={{ __html: q.explanation }} />
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {/* --- PAGINATION --- */}
      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-2 pt-6">
          <button 
            onClick={() => handlePageChange(currentPage - 1)}
            disabled={currentPage === 1}
            className="px-4 py-2 rounded-lg bg-white border border-slate-200 text-slate-600 font-bold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-50 transition-colors"
          >
            Prev
          </button>

          <div className="px-4 py-2 bg-slate-800 text-white rounded-lg font-bold text-sm shadow-lg">
            Page {currentPage} of {totalPages}
          </div>

          <button 
            onClick={() => handlePageChange(currentPage + 1)}
            disabled={currentPage === totalPages}
            className="px-4 py-2 rounded-lg bg-white border border-slate-200 text-slate-600 font-bold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-50 transition-colors"
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
};

