import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { Shuffle, Image as ImageIcon, CircleAlert, Eye, EyeOff, ChevronLeft, ChevronRight, Volume2, Filter, ChevronDown, RotateCw } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [ansImgError, setAnsImgError] = useState(false);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  const { speak, cancel, isSpeaking, activeType } = useSpeech();

  // Helper to remove HTML tags so the robot voice reads purely the text
  const stripHtml = (html: string) => {
    const tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  // Handle Filtering
  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [data, selectedCategories]);

  // Reset state when card changes
  useEffect(() => {
    setImgError(false);
    setAnsImgError(false);
    cancel(); // Stop audio when changing cards
  }, [currentIndex, deck, cancel]);

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  const flipCard = () => {
    if (!isAnimating) {
      // Stop audio if flipping
      if (isSpeaking) cancel();

      setIsAnimating(true);
      setIsFlipped(!isFlipped);
      setTimeout(() => setIsAnimating(false), 300);
    }
  };

  const nextCard = () => {
    if (currentIndex < deck.length - 1) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev + 1), 150);
    }
  };

  const prevCard = () => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev - 1), 150);
    }
  };

  const currentCard = deck[currentIndex];

  return (
    <div className="flex flex-col items-center justify-center max-w-3xl mx-auto w-full px-4 py-6 md:py-8 space-y-6">

      {/* --- TOP CONTROLS --- */}
      <div className="w-full flex flex-col md:flex-row justify-between items-center gap-4 relative z-20">
        <div className="bg-white px-4 py-2 rounded-xl border border-slate-200 shadow-sm font-bold text-slate-600 text-sm">
          {deck.length > 0 ? `${currentIndex + 1} / ${deck.length}` : '0 Cards'}
        </div>

        <div className="flex items-center gap-2 w-full md:w-auto">
          {/* Filter Dropdown */}
          <div className="relative flex-1 md:flex-none">
            <Button 
              variant="ghost" 
              onClick={() => setIsFilterOpen(!isFilterOpen)}
              className={`w-full flex items-center justify-center gap-2 text-xs font-bold rounded-xl border h-10 ${selectedCategories.length > 0 ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white border-slate-200'}`}
            >
              <Filter size={14} />
              {selectedCategories.length > 0 ? `${selectedCategories.length} Topics` : 'Filter'}
              <ChevronDown size={12} className={`transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} />
            </Button>

            {isFilterOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsFilterOpen(false)}></div>
                <div className="absolute right-0 top-full mt-2 w-72 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 flex flex-col max-h-[60vh]">
                  <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center rounded-t-xl">
                    <span className="text-xs font-bold text-slate-500 uppercase">Select Chapters</span>
                    <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-red-500 hover:text-red-700">Reset All</button>
                  </div>
                  <div className="overflow-y-auto p-2 custom-scrollbar">
                    {categories.map(cat => (
                      <label key={cat} className="flex items-center gap-3 p-2.5 hover:bg-slate-50 rounded-lg cursor-pointer transition-colors">
                        <div className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-colors ${selectedCategories.includes(cat) ? 'bg-blue-600 border-blue-600' : 'border-slate-300 bg-white'}`}>
                          {selectedCategories.includes(cat) && <Check size={12} className="text-white" />}
                        </div>
                        <span className="text-sm font-semibold text-slate-700">{cat}</span>
                        {/* Hidden checkbox for logic */}
                        <input 
                          type="checkbox" 
                          className="hidden"
                          checked={selectedCategories.includes(cat)}
                          onChange={() => toggleCategory(cat)}
                        />
                      </label>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>

          <Button 
            variant="ghost" 
            onClick={() => {
              const shuffled = [...deck].sort(() => Math.random() - 0.5);
              setDeck(shuffled);
              setCurrentIndex(0);
              setIsFlipped(false);
            }} 
            className="flex-1 md:flex-none h-10 text-xs font-bold text-slate-500 bg-white border border-slate-200 rounded-xl"
          >
            <Shuffle size={14} className="mr-1" /> Mix
          </Button>
        </div>
      </div>

      {/* --- THE CARD --- */}
      {deck.length > 0 ? (
        <div className="relative w-full aspect-[4/3] md:aspect-[16/9] cursor-pointer perspective-1000 z-10 group" onClick={flipCard}>
          <div className={`w-full h-full relative transform-style-3d transition-all duration-500 ease-out-back ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* FRONT (Question) */}
            <div className="absolute inset-0 w-full h-full bg-white rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.08)] border-2 border-slate-100 backface-hidden flex flex-col overflow-hidden">
              <div className="px-6 pt-5 flex justify-between items-start">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50 px-3 py-1 rounded-full border border-slate-100">
                  Question
                </span>
                <button 
                  onClick={(e) => speak(stripHtml(currentCard.questionText), currentCard.id, 'question', e)}
                  className={`p-2.5 rounded-full transition-all border ${isSpeaking && activeType === 'question' ? 'text-blue-600 bg-blue-50 border-blue-200 ring-4 ring-blue-100' : 'text-slate-300 bg-white border-slate-100 hover:text-blue-500 hover:border-blue-200'}`}
                >
                  <Volume2 size={20} />
                </button>
              </div>

              <div className="flex-1 p-6 md:p-10 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && !imgError && (
                  <div className="mb-6 bg-slate-50 p-2 rounded-xl border border-slate-100">
                    <img 
                      src={currentCard.questionImage} 
                      className="max-h-40 md:max-h-56 object-contain rounded-lg mix-blend-multiply"
                      onError={() => setImgError(true)}
                      alt="Question Diagram"
                    />
                  </div>
                )}
                <div 
                  className="text-xl md:text-3xl font-bold text-center text-slate-800 leading-snug"
                  dangerouslySetInnerHTML={{ __html: currentCard.questionText }}
                />
              </div>
              <div className="h-10 bg-slate-50 border-t border-slate-100 flex items-center justify-center text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">
                Tap to Flip
              </div>
            </div>

            {/* BACK (Answer) */}
            <div className="absolute inset-0 w-full h-full bg-slate-900 rounded-3xl shadow-[0_20px_50px_rgb(15,23,42,0.3)] border border-slate-800 backface-hidden rotate-y-180 flex flex-col overflow-hidden">
              <div className="px-6 pt-5 flex justify-between items-center">
                <span className="text-[10px] font-black uppercase text-emerald-400 tracking-widest bg-emerald-400/10 px-3 py-1 rounded-full border border-emerald-400/20">
                  Answer
                </span>
                <button 
                  onClick={(e) => speak(stripHtml(currentCard.answerText), currentCard.id, 'answer', e)}
                  className={`p-2.5 rounded-full transition-all border ${isSpeaking && activeType === 'answer' ? 'text-emerald-400 bg-emerald-400/10 border-emerald-400/30 ring-4 ring-emerald-400/20' : 'text-slate-600 bg-slate-800 border-slate-700 hover:text-emerald-400 hover:border-emerald-400/50'}`}
                >
                  <Volume2 size={20} />
                </button>
              </div>

              <div className="flex-1 p-6 md:p-10 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.answerImage && !ansImgError && (
                  <div className="mb-6 bg-white p-2 rounded-xl">
                    <img 
                      src={currentCard.answerImage} 
                      className="max-h-40 md:max-h-56 object-contain rounded-lg"
                      onError={() => setAnsImgError(true)}
                      alt="Answer Diagram"
                    />
                  </div>
                )}

                <div 
                  className="text-xl md:text-3xl font-bold text-center text-white leading-relaxed mb-4"
                  dangerouslySetInnerHTML={{ __html: currentCard.answerText }}
                />

                {currentCard.explanation && (
                  <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700/50 text-slate-400 text-sm leading-relaxed max-w-lg text-center backdrop-blur-sm">
                    <span className="text-slate-500 font-bold uppercase text-[10px] tracking-widest block mb-1">Explanation</span>
                    <span dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                  </div>
                )}
              </div>
              <div className="h-10 bg-slate-950/30 border-t border-slate-800/50 flex items-center justify-center text-[10px] font-bold text-slate-600 uppercase tracking-[0.2em]">
                Tap to Flip Back
              </div>
            </div>
          </div>
        </div>
      ) : (
        <div className="w-full aspect-video flex flex-col items-center justify-center bg-white rounded-3xl border-2 border-dashed border-slate-300 text-slate-400 p-8 text-center">
          <Filter size={48} className="mb-4 opacity-20" />
          <p className="font-bold text-lg">No cards match this filter.</p>
          <button onClick={() => setSelectedCategories([])} className="mt-2 text-blue-500 font-bold hover:underline">Clear Filters</button>
        </div>
      )}

      {/* --- NAVIGATION BUTTONS --- */}
      <div className="grid grid-cols-2 md:flex md:items-center md:justify-center gap-4 w-full pt-4">
        <button 
          onClick={prevCard}
          disabled={currentIndex === 0}
          className="h-14 md:w-20 md:h-20 rounded-2xl md:rounded-full bg-white border-2 border-slate-100 text-slate-400 hover:text-blue-600 hover:border-blue-200 hover:bg-blue-50 hover:shadow-lg transition-all disabled:opacity-30 disabled:cursor-not-allowed flex items-center justify-center"
        >
          <ChevronLeft size={32} />
        </button>

        <button 
          onClick={flipCard} 
          className="col-span-2 order-first md:order-none h-16 md:h-14 px-8 rounded-2xl md:rounded-full bg-slate-900 text-white font-bold uppercase tracking-widest shadow-xl shadow-slate-900/20 hover:bg-blue-600 hover:shadow-blue-600/30 hover:-translate-y-1 active:translate-y-0 transition-all flex items-center justify-center gap-3 text-sm md:text-xs"
        >
          <RotateCw size={18} className={isFlipped ? "-rotate-180 transition-transform duration-500" : "transition-transform duration-500"} />
          {isFlipped ? 'Show Question' : 'Show Answer'}
        </button>

        <button 
          onClick={nextCard}
          disabled={currentIndex === deck.length - 1}
          className="h-14 md:w-20 md:h-20 rounded-2xl md:rounded-full bg-white border-2 border-slate-100 text-slate-400 hover:text-blue-600 hover:border-blue-200 hover:bg-blue-50 hover:shadow-lg transition-all disabled:opacity-30 disabled:cursor-not-allowed flex items-center justify-center"
        >
          <ChevronRight size={32} />
        </button>
      </div>
    </div>
  );
};

